sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// Draft from Templates Update- UI- Add "Draft Template" Action Button
// changed the button name and the button caption and the condition to prevent draft added below active task
generate_draft_tasks();

function generate_draft_tasks(){
	// this action creates the tasks in draft state
	current.u_create_tasks_in_draft_state=true;
	new Template_uiAction().uiAction_Start_Template(current);  
	// Redirect platform to stay on template
	if (typeof spModal == 'undefined' ) {
		var task = new GlideRecord('x_153465_discovert_route_task_instance');
		if(task.get(current.getValue('parent_task'))){
			action.setRedirectURL(task);
		} else {
			var temp = new GlideRecord('x_153465_discovert_discover_routing_template');
			if(temp.get(current.getValue('routing_template_ref'))){
				action.setRedirectURL(temp);
			}
		}
		gs.addInfoMessage('Success! Tasker is starting the selected template.');
	}
}
